"use client";

import { useRef, useCallback } from "react";

// Paths from lucide-react arrow-right (inspected from lucide.dev)
// path[0] → d="M5 12h14"      = the horizontal line
// path[1] → d="m12 5 7 7-7 7" = the arrowhead (relative coords)

type Variant = "slide" | "bounce" | "pulse";

const VARIANTS: Record<
  Variant,
  {
    trigger: "hover" | "click" | "loop";
    duration: number;
    easing: string;
    keyframes: {
      line?: Keyframe[];
      arrowHead?: Keyframe[];
    };
  }
> = {
  slide: {
    trigger: "hover",
    duration: 400,
    easing: "ease-out",
    keyframes: {
      line: [
        { transform: "translateX(0)", offset: 0 },
        { transform: "translateX(4px)", offset: 0.4 },
        { transform: "translateX(0)", offset: 1 },
      ],
      arrowHead: [
        { opacity: 1, transform: "translateX(0)", offset: 0 },
        { opacity: 0, transform: "translateX(8px)", offset: 0.3 },
        { opacity: 0, transform: "translateX(-8px)", offset: 0.5 },
        { opacity: 1, transform: "translateX(0)", offset: 1 },
      ],
    },
  },

  bounce: {
    trigger: "hover",
    duration: 600,
    easing: "ease-in-out",
    keyframes: {
      line: [
        { transform: "translateX(0)", offset: 0 },
        { transform: "translateX(6px)", offset: 0.35 },
        { transform: "translateX(-2px)", offset: 0.65 },
        { transform: "translateX(0)", offset: 1 },
      ],
      arrowHead: [
        { transform: "translateX(0)", offset: 0 },
        { transform: "translateX(6px)", offset: 0.35 },
        { transform: "translateX(-2px)", offset: 0.65 },
        { transform: "translateX(0)", offset: 1 },
      ],
    },
  },

  pulse: {
    trigger: "loop",
    duration: 1400,
    easing: "ease-in-out",
    keyframes: {
      arrowHead: [
        { opacity: 0.2, transform: "translateX(-3px)", offset: 0 },
        { opacity: 1, transform: "translateX(3px)", offset: 0.5 },
        { opacity: 0.2, transform: "translateX(-3px)", offset: 1 },
      ],
    },
  },
};

interface Props {
  size?: number;
  variant?: Variant;
  color?: string;
  className?: string;
}

export function ArrowRight({
  size = 24,
  variant = "slide",
  color,
  className = "",
}: Props) {
  const svgRef = useRef<SVGSVGElement>(null);
  const cfg = VARIANTS[variant];
  const animsRef = useRef<Animation[]>([]);

  const play = useCallback(() => {
    if (!svgRef.current) return;
    // cancel any running animations first
    animsRef.current.forEach((a) => a.cancel());
    animsRef.current = [];

    const opts: KeyframeAnimationOptions = {
      duration: cfg.duration,
      easing: cfg.easing,
      fill: "forwards",
      iterations: cfg.trigger === "loop" ? Infinity : 1,
    };

    for (const [id, frames] of Object.entries(cfg.keyframes)) {
      const el = svgRef.current.querySelector<SVGElement>(`[data-id="${id}"]`);
      if (!el || !frames) continue;
      animsRef.current.push(el.animate(frames, opts));
    }
  }, [cfg]);

  // Start loop variants automatically on mount
  const mountRef = useRef(false);
  const svgCallbackRef = useCallback(
    (node: SVGSVGElement | null) => {
      (svgRef as React.MutableRefObject<SVGSVGElement | null>).current = node;
      if (node && cfg.trigger === "loop" && !mountRef.current) {
        mountRef.current = true;
        setTimeout(play, 0);
      }
    },
    [cfg.trigger, play],
  );

  const handlers =
    cfg.trigger === "hover"
      ? { onMouseEnter: play }
      : cfg.trigger === "click"
        ? { onClick: play }
        : {};

  return (
    <svg
      ref={cfg.trigger === "loop" ? svgCallbackRef : svgRef}
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke={color ?? "currentColor"}
      strokeWidth={2}
      strokeLinecap="round"
      strokeLinejoin="round"
      className={className}
      style={{ cursor: cfg.trigger === "hover" ? "pointer" : "default" }}
      {...handlers}
    >
      {/* path from lucide arrow-right: the horizontal line */}
      <path data-id="line" d="M5 12h14" />
      {/* path from lucide arrow-right: the arrowhead chevron */}
      <path
        data-id="arrowHead"
        d="m12 5 7 7-7 7"
        style={{ transformOrigin: "12px 12px" }}
      />
    </svg>
  );
}

export default ArrowRight;
